#!/bin/bash
# WFid 一键部署脚本
# 用法: bash wfid-deploy.sh <your-github-token>

set -e

GITHUB_TOKEN="$1"

if [ -z "$GITHUB_TOKEN" ]; then
    echo "用法: bash wfid-deploy.sh <your-github-token>"
    echo ""
    echo "请提供GitHub Personal Access Token"
    echo "获取地址: https://github.com/settings/tokens/new"
    echo "需要勾选: repo, workflow"
    exit 1
fi

echo "🚀 WFid - 一键部署到GitHub Pages"
echo "================================"
echo ""

# 验证Token
echo "📋 验证Token..."
USER_INFO=$(curl -s -H "Authorization: token $GITHUB_TOKEN" https://api.github.com/user)
USER_NAME=$(echo "$USER_INFO" | python3 -c "import sys,json; d=json.load(sys.stdin); print(d.get('login',''))" 2>/dev/null)

if [ -z "$USER_NAME" ]; then
    echo "❌ Token验证失败，请检查Token是否正确"
    exit 1
fi

echo "✅ Token有效! 欢迎, $USER_NAME"
echo ""

# 创建临时目录
TEMP_DIR=$(mktemp -d)
echo "📁 工作目录: $TEMP_DIR"
cd "$TEMP_DIR"

# 初始化git
git init
git remote add origin "https://$GITHUB_TOKEN@github.com/Whu52052/WFid.git"

echo "📦 解压项目文件..."

mkdir -p "$(dirname 'tsconfig.json')"
echo '" | base64 -d > "tsconfig.json"

